    fix_wg: bool = False
    fixed_wg: float = 0.5
    fix_wl: bool = False
    fixed_wl: float = 0.5
    aki_threshold: float = 0.0
    ne_low: float = 1e15
    ne_high: float = 1e18
    kt_low: float = 0.5
    kt_high: float = 3.0
    show_progress: bool = True
    fix_wavelength: bool = False
    convert_to_angstrom: bool = False
    iterations: int = 20
    auto_offset: bool = False
    auto_shift: float = 0.0
    ha_lines: int = 1
    ha_range: float = 150.0
    ha_wl1: float = 6565.0
    ha_wl2: float = 6490.0
    ha_dl1: float = 40.0
    ha_dl2: float = 50.0
    ha_kt: float = 1.0
