@dataclass
class Spectrum:
    x: list[float] = field(default_factory=list)
    y: list[float] = field(default_factory=list)
    name: str = "Spectrum"
    filename: str = ""
    visible: bool = True
    color: Optional[str] = None

    @classmethod
    def from_ascii(cls, filename: str, convert_nm_to_a: bool = False, name: Optional[str] = None) -> "Spectrum":
        xs, ys = [], []
        with open(filename, "r", encoding="utf-8", errors="ignore") as f:
            for line in f:
                line = line.strip().replace(",", ".")
                if not line or line.startswith("#"):
                    continue
                p = line.split()
                if len(p) < 2:
                    continue
                try:
                    wave = float(p[0])
                    inten = float(p[1])
                except Exception:
                    continue
                if convert_nm_to_a and wave < 1500:
                    wave *= 10.0
                xs.append(wave)
                ys.append(inten)
        if not xs:
            raise ValueError("Il file non contiene dati numerici a due colonne.")
        return cls(xs, ys, name or Path(filename).name, filename)

    @classmethod
    def from_roh(cls, filename: str, convert_nm_to_a: bool = False, limit_low: Optional[float] = None, limit_high: Optional[float] = None, name: Optional[str] = None) -> "Spectrum":
        data = Path(filename).read_bytes()
        if len(data) < 4:
            raise ValueError("File .ROH troppo corto o corrotto.")
        total = len(data) // 4
        offset = 0

        def read_float(label: str) -> float:
            nonlocal offset
            if offset >= total:
                raise ValueError(f"File .ROH troppo corto durante la lettura di {label}.")
            value = struct.unpack_from("<f", data, offset * 4)[0]
            offset += 1
            return value

        def skip(count: int, label: str):
            nonlocal offset
            if offset + count > total:
                raise ValueError(f"File .ROH troppo corto durante il salto di {label}.")
            offset += count

        version = read_float("version")
        if version < 70:
            start_w = read_float("start_w")
            res_w = read_float("res_w")
            quadr = read_float("quadr")
            cub = read_float("cub")
            skip(11, "header")
            npoints = safe_int(read_float("npoints"), 0)
            skip(3, "header")
            start_index, end_index = 0, npoints
        else:
            skip(73, "header")
            start_w = read_float("start_w")
            res_w = read_float("res_w")
            quadr = read_float("quadr")
            cub = read_float("cub")
            read_float("quart")
            start_index = safe_int(read_float("startt"), 0)
            end_index = safe_int(read_float("endd"), 0)
            skip(19, "header")

        if end_index <= start_index:
            raise ValueError("File .ROH senza punti spettrali validi.")
        needed = end_index - start_index
        if offset + needed > total:
            raise ValueError("File .ROH troppo corto durante la lettura delle intensità.")

        lo = min(limit_low, limit_high) if limit_low is not None and limit_high is not None else None
        hi = max(limit_low, limit_high) if limit_low is not None and limit_high is not None else None
        xs, ys = [], []
        for nq in range(start_index, end_index):
            wave = start_w + nq * res_w + quadr * nq * nq + cub * nq * nq * nq
            inten = read_float("intensity")
            if convert_nm_to_a and wave < 1500:
                wave *= 10.0
            if lo is not None and hi is not None and not (lo <= wave <= hi):
                continue
            xs.append(wave)
            ys.append(inten)
        if not xs:
            raise ValueError("File .ROH senza punti nel range di lunghezze d'onda impostato.")
        return cls(xs, ys, name or Path(filename).name, filename)

    def save_ascii(self, filename: str):
        with open(filename, "w", encoding="utf-8") as f:
            for x, y in zip(self.x, self.y):
                f.write(f"{x:.8g} {y:.8g}\n")

    def smooth(self, window: int = 11, polyorder: int = 4):
        if len(self.y) < 3:
            return
        if window % 2 == 0:
            window += 1
        window = max(3, min(window, len(self.y) - (1 - len(self.y) % 2)))
        if savgol_filter is not None and np is not None and len(self.y) > window:
            self.y = savgol_filter(np.asarray(self.y), window, min(polyorder, window - 1)).tolist()
        else:
            half = window // 2
            self.y = [sum(self.y[max(0, i-half):min(len(self.y), i+half+1)]) / (min(len(self.y), i+half+1)-max(0, i-half)) for i in range(len(self.y))]

    def apply_response(self, response: "ResponseCurve"):
        if not response.x:
            return
        self.y = [yy / response.value_at(xx) if response.value_at(xx) else yy for xx, yy in zip(self.x, self.y)]

    def shifted(self, offset: float, name: str) -> "Spectrum":
        return Spectrum(list(self.x), [v + offset for v in self.y], name=name)

    def scaled(self, factor: float, name: str) -> "Spectrum":
        return Spectrum(list(self.x), [v * factor for v in self.y], name=name)


LIBS_SPECTRUM_COLORS = ["black", "red", "blue", "green", "magenta", "cyan", "orange", "brown"]


def default_spectrum_color(index: int) -> str:
    if index < len(LIBS_SPECTRUM_COLORS):
        return LIBS_SPECTRUM_COLORS[index]
    try:
        cycle = matplotlib.rcParams["axes.prop_cycle"].by_key().get("color", [])
    except Exception:
        cycle = []
    if cycle:
        return cycle[(index - len(LIBS_SPECTRUM_COLORS)) % len(cycle)]
    return LIBS_SPECTRUM_COLORS[index % len(LIBS_SPECTRUM_COLORS)]


def assign_default_spectrum_color(sp: Spectrum, index: int) -> Spectrum:
    if not getattr(sp, "color", None):
        sp.color = default_spectrum_color(index)
    return sp


def _interp_spectrum_value(points: list[tuple[float, float]], wavelength: float) -> float:
    if wavelength <= points[0][0]:
        return points[0][1]
    if wavelength >= points[-1][0]:
        return points[-1][1]
    for i in range(1, len(points)):
        x1, y1 = points[i]
        if wavelength <= x1:
            x0, y0 = points[i - 1]
            if x1 == x0:
                return (y0 + y1) / 2.0
            return y0 + (y1 - y0) * (wavelength - x0) / (x1 - x0)
    return points[-1][1]


def merge_spectra_by_wavelength(first: Spectrum, second: Spectrum, name: str = "Merged spectrum") -> Spectrum:
    """Merge two spectra by wavelength, averaging intensities in the overlap."""
    p1 = sorted(zip(first.x, first.y), key=lambda p: p[0])
    p2 = sorted(zip(second.x, second.y), key=lambda p: p[0])
    if not p1:
        return Spectrum([x for x, _ in p2], [y for _, y in p2], name=name, filename=second.filename)
    if not p2:
        return Spectrum([x for x, _ in p1], [y for _, y in p1], name=name, filename=first.filename)

    lo1, hi1 = p1[0][0], p1[-1][0]
    lo2, hi2 = p2[0][0], p2[-1][0]
    overlap_lo = max(lo1, lo2)
    overlap_hi = min(hi1, hi2)

    merged: list[tuple[float, float]] = []
    if overlap_lo <= overlap_hi:
        merged.extend((x, y) for x, y in p1 if x < overlap_lo or x > overlap_hi)
        merged.extend((x, y) for x, y in p2 if x < overlap_lo or x > overlap_hi)
        overlap_x = sorted({x for x, _ in p1 if overlap_lo <= x <= overlap_hi} |
                           {x for x, _ in p2 if overlap_lo <= x <= overlap_hi})
        for x in overlap_x:
            y = (_interp_spectrum_value(p1, x) + _interp_spectrum_value(p2, x)) / 2.0
            merged.append((x, y))
    else:
        merged.extend(p1)
        merged.extend(p2)

    merged.sort(key=lambda p: p[0])
    return Spectrum([x for x, _ in merged], [y for _, y in merged], name=name)


def load_spectrum_for_open(filename: str, options: AppOptions) -> Spectrum:
    if Path(filename).suffix.lower() == ".roh":
        return Spectrum.from_roh(
            filename,
            getattr(options, "convert_to_angstrom", False),
            getattr(options, "limit_low", None),
            getattr(options, "limit_high", None),
        )
    return Spectrum.from_ascii(filename, getattr(options, "convert_to_angstrom", False))


@dataclass
class ResponseCurve:
    x: list[float] = field(default_factory=list)
    y: list[float] = field(default_factory=list)
    filename: str = ""

    @classmethod
    def from_ascii(cls, filename: str, convert_nm_to_a: bool = False):
        sp = Spectrum.from_ascii(filename, convert_nm_to_a)
        return cls(sp.x, sp.y, filename)

    def value_at(self, wavelength: float) -> float:
        if not self.x:
            return 1.0
        pairs = sorted(zip(self.x, self.y), key=lambda p: p[0])
        xs, ys = [p[0] for p in pairs], [p[1] for p in pairs]
        if wavelength <= xs[0]:
            return ys[0]
        if wavelength >= xs[-1]:
            return ys[-1]
        for i in range(1, len(xs)):
            if wavelength < xs[i]:
                x0, x1, y0, y1 = xs[i-1], xs[i], ys[i-1], ys[i]
                return y1 + (y0 - y1) / (x0 - x1) * (wavelength - x1) if x0 != x1 else y1
        return 1.0


@dataclass
class TemplateLine:
    wavelen: float
    specie: str = ""
    ion: int = 0
    asswavelen: float = 0.0
    inte: float = 0.0
    ei: float = 0.0
    wg: float = 0.0
    wl: float = 0.0
    ek: float = 0.0
    aki: float = 0.0
    gk: int = 0
    gi: int = 0
    fitwavelen: float = 0.0
    templint: float = 0.0
    error_inte: float = 0.0
