        self.spectra.clear()
        self.clear_plot_annotations()
        self.clear_template_data()
        self.redraw()
        if self.active_window and self.active_window.winfo_exists():
            self.active_window.refresh()
        self.status("Clear Graph: all spectra cleared.")

